/**
 * 工作流配置（请按需修改）
 * - rssList：每个 YouTube 频道的 RSS
 *   示例：https://www.youtube.com/feeds/videos.xml?channel_id=UCxxxx
 * - lookbackHours：只处理「发布时间」落在此窗口内的视频，避免首次运行刷旧片
 * - openaiModel：模型名（须与「OpenAI 摘要」凭据所用服务兼容）
 * - telegramChatId：你的 Telegram 数字 chat_id
 * API 地址在 n8n 的 OpenAI 凭据里配置（与飞书工作流相同）。
 */
const CONFIG = {
  rssList: [
    'https://www.youtube.com/feeds/videos.xml?channel_id=UCxxxxxxxxxxxxxxxxxxxxxx',
  ],
  lookbackHours: 24,
  openaiModel: 'gpt-4o-mini',
  telegramChatId: '123456789',
};

const { rssList, ...rest } = CONFIG;
return rssList
  .map((u) => (u || '').trim())
  .filter(Boolean)
  .map((rssUrl) => ({ json: { rssUrl, config: rest } }));

const item = $json;
const cfg = item.config || $('配置与展开 RSS').first().json.config;
const link = typeof item.link === 'string' ? item.link : item.link?.__text || item.link?.href || '';
const title = item.title || '';
const pubDate = item.pubDate || item.isoDate || '';

let videoId = '';
const mWatch = link.match(/[?&]v=([a-zA-Z0-9_-]{11})/);
const mShort = link.match(/\/shorts\/([a-zA-Z0-9_-]{11})/);
if (mWatch) videoId = mWatch[1];
else if (mShort) videoId = mShort[1];

return [
  {
    json: {
      videoId,
      title,
      link,
      pubDate,
      config: cfg,
    },
  },
];

const items = $input.all();
const cfg = items[0]?.json?.config;
const lookbackMs = (cfg?.lookbackHours ?? 24) * 60 * 60 * 1000;
const cutoff = Date.now() - lookbackMs;

const byId = new Map();
for (const it of items) {
  const j = it.json;
  if (!j.videoId) continue;
  const t = Date.parse(j.pubDate);
  if (Number.isFinite(t) && t < cutoff) continue;
  if (!byId.has(j.videoId)) byId.set(j.videoId, j);
}

return [...byId.values()].map((j) => ({ json: j }));

const staticData = $getWorkflowStaticData('global');
staticData.seenVideoIds = staticData.seenVideoIds || {};

const out = [];
for (const it of $input.all()) {
  const j = it.json;
  if (!j.videoId) continue;
  if (staticData.seenVideoIds[j.videoId]) continue;
  out.push({ json: j });
}
return out;

/**
 * 从 YouTube 页面解析 captionTracks，拉取字幕 XML 并拼成纯文本。
 * 无字幕 / 尚未生成自动字幕时 transcript 为空 → 不写 seen，下一轮到齐后再推。
 */

function extractPlayerResponse(html) {
  const needles = ['var ytInitialPlayerResponse = ', 'ytInitialPlayerResponse = '];
  for (const n of needles) {
    const i = html.indexOf(n);
    if (i === -1) continue;
    let s = i + n.length;
    // 跳过可能的空白与 JSON.parse( 包裹（保守：仍以 { 开头解析）
    while (s < html.length && html[s] === ' ') s += 1;
    if (html.startsWith('JSON.parse("', s)) {
      // 复杂转义场景：跳过，换下一 needle
      continue;
    }
    if (html[s] !== '{') continue;
    let depth = 0;
    let e = s;
    for (; e < html.length; e++) {
      const c = html[e];
      if (c === '{') depth++;
      else if (c === '}') {
        depth--;
        if (depth === 0) {
          e++;
          break;
        }
      }
    }
    try {
      return JSON.parse(html.slice(s, e));
    } catch (err) {
      continue;
    }
  }
  return null;
}

function pickCaptionTrack(tracks) {
  if (!tracks?.length) return null;
  const rank = (lang) => {
    const l = (lang || '').toLowerCase();
    if (l === 'zh' || l.startsWith('zh-hans')) return 0;
    if (l.startsWith('zh')) return 1;
    if (l === 'en' || l.startsWith('en-')) return 2;
    return 5;
  };
  return [...tracks].sort((a, b) => rank(a.languageCode) - rank(b.languageCode))[0];
}

function xmlishToText(raw) {
  return raw
    .replace(/<[^>]+>/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/\s+/g, ' ')
    .trim();
}

const videoId = $json.videoId;
const title = $json.title;
const link = $json.link;
const pubDate = $json.pubDate;
const config = $json.config;

let transcript = '';
let transcriptLang = '';

try {
  const watchUrl = `https://www.youtube.com/watch?v=${videoId}`;
  const html = await $helpers.httpRequest({
    method: 'GET',
    url: watchUrl,
    headers: {
      'User-Agent':
        'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/124.0.0.0 Safari/537.36',
      'Accept-Language': 'zh-CN,zh;q=0.9,en;q=0.8',
    },
  });

  const pr = extractPlayerResponse(html);
  const tracks = pr?.captions?.playerCaptionsTracklistRenderer?.captionTracks;
  const track = pickCaptionTrack(tracks);

  if (track?.baseUrl) {
    transcriptLang = track.languageCode || '';
    const xml = await $helpers.httpRequest({
      method: 'GET',
      url: `${track.baseUrl}&fmt=srv3`,
      headers: {
        'User-Agent':
          'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/124.0.0.0 Safari/537.36',
      },
    });
    transcript = xmlishToText(String(xml));
  }
} catch (e) {
  transcript = '';
}

return [{ json: { videoId, title, link, pubDate, config, transcript, transcriptLang } }];

const title = $json.title || '';
const link = $json.link || '';
const lang = $json.transcriptLang || 'unknown';
const transcript = String($json.transcript || '').slice(0, 48000);

const llmUserContent =
  '视频标题：' +
  title +
  '\n视频链接：' +
  link +
  '\n字幕语言：' +
  lang +
  '\n\n以下为自动字幕拼合文本（可能含口误/同音错字）：\n\n' +
  transcript;

return [
  {
    json: {
      videoId: $json.videoId,
      title,
      link,
      transcriptLang: $json.transcriptLang,
      config: $json.config,
      llmUserContent,
    },
  },
];

// 与飞书工作流一致：OpenAI 节点可能返回 message.content 或 choices[].message.content
const summary = (
  $json.message?.content ||
  $json.choices?.[0]?.message?.content ||
  ''
).trim();
const meta = $('拉取逐字稿').item.json;
return [
  {
    json: {
      videoId: meta.videoId,
      title: meta.title,
      link: meta.link,
      summary,
      transcriptLang: meta.transcriptLang,
      config: meta.config,
    },
  },
];

const staticData = $getWorkflowStaticData('global');
staticData.seenVideoIds = staticData.seenVideoIds || {};
const vid = $('合并推送字段').item.json.videoId;
if (vid) staticData.seenVideoIds[vid] = { at: Date.now() };
return $input.all();
